use near_sdk::{json_types::U64, near, store::IterableMap, IntoStorageKey};
use primitive_types::U256;
use redstone::{
    contract::verification,
    core::{process_payload, processor_result::ValidatedPayload},
    network::{error::Error as RedStoneError, StdEnv},
    ConfigFactory, FeedValue,
};

use super::{
    config::{Config, DATA_STALENESS},
    feed_data::FeedData,
    FeedId, GetPrices,
};

#[derive(Debug)]
#[near(serializers = [borsh])]
pub struct RedStoneAdapter {
    pub config: Config,
    feeds: IterableMap<FeedId, FeedData>,
}

impl RedStoneAdapter {
    pub fn new(prefix: impl IntoStorageKey, config: Config) -> Self {
        Self {
            config,
            feeds: IterableMap::new(prefix),
        }
    }

    /// Retrieves fresh feed data from storage.
    ///
    /// # Errors
    ///
    /// - Feed does not exist.
    /// - [`RedStoneError`] (e.g. data too stale)
    pub fn feed_data<'a>(
        &'a self,
        feed_id: &FeedId,
        timestamp_ms: u64,
    ) -> Option<Result<&'a FeedData, RedStoneError>> {
        let f = self.feeds.get(feed_id)?;

        Some(
            verification::verify_data_staleness(
                f.write_timestamp.0.into(),
                timestamp_ms.into(),
                DATA_STALENESS,
            )
            .map(|()| f),
        )
    }

    fn update_feed(
        &mut self,
        is_trusted: bool,
        feed_id: &FeedId,
        feed_data: FeedData,
    ) -> Result<FeedData, RedStoneError> {
        let now = feed_data.write_timestamp.0.into();
        let new_pkg = feed_data.package_timestamp.0.into();

        let old = self.feeds.get(feed_id);
        let old_write = old.map(|d| d.write_timestamp.0.into());
        let old_pkg = old.map(|d| d.package_timestamp.0.into());

        if is_trusted {
            verification::verify_trusted_update(now, old_write, old_pkg, new_pkg)?;
        } else {
            let interval = self.config.min_interval_between_updates_ms.into();
            verification::verify_untrusted_update(now, old_write, interval, old_pkg, new_pkg)?;
        }

        self.feeds.insert(feed_id.clone(), feed_data.clone());

        Ok(feed_data)
    }

    /// Validates a payload and extracts feed values.
    ///
    /// # Errors
    ///
    /// - [`RedStoneError`]
    pub fn validate_payload(
        &self,
        feed_ids: &[FeedId],
        payload: &[u8],
        timestamp_ms: u64,
    ) -> Result<ValidatedPayload, RedStoneError> {
        let feed_ids = feed_ids
            .iter()
            .map(|id| id.as_bytes().to_vec().into())
            .collect();

        let mut config =
            self.config
                .redstone_config::<StdEnv>((), feed_ids, timestamp_ms.into())?;
        process_payload(&mut config, payload.to_vec())
    }

    /// Validates prices given a payload. For pull-style usage (payload is
    /// attached to original transaction). Does not write to storage.
    ///
    /// # Errors
    ///
    /// - Feed ID is unknown or missing from payload.
    /// - [`RedStoneError`]
    pub fn get_prices(
        &self,
        feed_ids: &[FeedId],
        payload: &[u8],
        timestamp_ms: u64,
    ) -> Result<GetPrices, RedStoneError> {
        let ValidatedPayload { timestamp, values } =
            self.validate_payload(feed_ids, payload, timestamp_ms)?;

        Ok(GetPrices {
            timestamp: U64(timestamp.as_millis()),
            prices: values
                .into_iter()
                .map(|f| {
                    let value = U256::from_big_endian(f.value.as_be_bytes()).into();
                    (f.feed.into(), value)
                })
                .collect(),
        })
    }

    /// Write price data to storage.
    ///
    /// # Errors
    ///
    /// - [`RedStoneError`]
    pub fn write_prices(
        &mut self,
        is_trusted: bool,
        payload: ValidatedPayload,
        timestamp_ms: u64,
    ) -> Vec<(FeedId, Result<FeedData, RedStoneError>)> {
        payload
            .values
            .into_iter()
            .map(|FeedValue { feed, value }| {
                let feed_id: super::FeedId = feed.into();
                let feed_data = FeedData {
                    price: U256::from_big_endian(value.as_be_bytes()).into(),
                    package_timestamp: U64(payload.timestamp.as_millis()),
                    write_timestamp: U64(timestamp_ms),
                };
                let update = self.update_feed(is_trusted, &feed_id, feed_data);

                (feed_id, update)
            })
            .collect()
    }
}

#[allow(clippy::cast_sign_loss)]
#[cfg(test)]
mod tests {
    use hex_literal::hex;
    use near_sdk::json_types::U64;
    use primitive_types::U256;

    use super::*;

    use crate::oracle::redstone::config;

    #[rstest::rstest]
    #[case::stellar(1_770_985_144_000, &hex!(""))]
    #[case::js_sdk(1_771_336_150_000, &hex!(""))]
    #[should_panic = "called `Option::unwrap()` on a `None` value"]
    #[case::stellar_feed_id(1_770_985_144_000, &hex!(""))]
    #[should_panic = "TooOld"]
    #[case::stellar_timestamp_old(2_770_985_144_000, &hex!(""))]
    #[should_panic = "TooFuture"]
    #[case::stellar_timestamp_future(1_270_985_144_000, &hex!(""))]
    #[should_panic = "called `Option::unwrap()` on a `None` value"]
    #[case::js_sdk_feed_id(1_771_336_150_000, &hex!(""))]
    fn payload(#[case] timestamp: u64, #[case] input: &[u8]) {
        let mut ra = RedStoneAdapter::new(b"a", config::prod());

        let eth = FeedId::from("ETH");
        let btc = FeedId::from("BTC");

        let prices = vec![eth.clone(), btc.clone()];

        let p = ra.validate_payload(&prices, input, timestamp).unwrap();
        ra.write_prices(true, p, timestamp)
            .into_iter()
            .for_each(|(_, r)| {
                r.unwrap();
            });

        let _eth_data = ra.feed_data(&eth, timestamp).unwrap();
        let _btc_data = ra.feed_data(&btc, timestamp).unwrap();
    }

    #[rstest::rstest]
    fn output() {
        let timestamp = 1_770_985_144_000_u64;
        let input = hex!("");

        let mut ra = RedStoneAdapter::new(b"a", config::prod());

        let eth = FeedId::from("ETH");
        let btc = FeedId::from("BTC");

        let prices = vec![eth.clone(), btc.clone()];

        let p = ra.validate_payload(&prices, &input, timestamp).unwrap();
        let written = ra
            .write_prices(true, p, timestamp)
            .into_iter()
            .map(|(_, r)| r.unwrap())
            .collect::<Vec<_>>();
        assert_eq!(written.len(), 2);

        let eth_data = ra.feed_data(&eth, timestamp).unwrap().unwrap();
        let btc_data = ra.feed_data(&btc, timestamp).unwrap().unwrap();

        assert_eq!(
            eth_data,
            &FeedData {
                price: U256::from(195_692_129_540_u128).into(),
                package_timestamp: U64(1_770_985_144_000),
                write_timestamp: U64(1_770_985_144_000),
            },
        );

        assert_eq!(
            btc_data,
            &FeedData {
                price: U256::from(6_698_556_748_915_u128).into(),
                package_timestamp: U64(1_770_985_144_000),
                write_timestamp: U64(1_770_985_144_000),
            },
        );
    }
}
